102	const claimStep = (policy: Policy, incident: Incident): { result: ClaimResult; policy: Policy } => {
103	  const payout = incident.damages.reduce(
104	    (sum, dmg) => sum + (dmg.amount - DEDUCTIBLE),
105	    0,
106	  );
107	  const remainingCap = policy.remainingCap - payout;
108	  return {
109	    result: { payout, remainingCap },
110	    policy: { ...policy, remainingCap },
111	  };
112	};
