type ScenarioState = {
  results: StepResult[];
  quoteIndex: number;
  policies: Record<number, Policy>;
};

const initialState: ScenarioState = { results: [], quoteIndex: 0, policies: {} };

const applyStep = (
  customer: Customer,
  state: ScenarioState,
  step: Step,
  index: number,
): ScenarioState => {
  if (step.op === "quote") {
    const result = quoteStep(customer, state.quoteIndex, step.items);
    return {
      results: [...state.results, result],
      quoteIndex: state.quoteIndex + 1,
      policies: { ...state.policies, [index]: policyFromItems(step.items) },
    };
  }
  const { result, policy } = claimStep(state.policies[step.policy], step.incident);
  return {
    results: [...state.results, result],
    quoteIndex: state.quoteIndex,
    policies: { ...state.policies, [step.policy]: policy },
  };
};

export const runScenario = (scenario: unknown): unknown => {
  const { customer, steps } = scenario as Scenario;
  const { results } = steps.reduce(
    (state, step, index) => applyStep(customer, state, step, index),
    initialState,
  );
  return { results };
};
